/* ─── BMR Calculator ─── */
function calcNutrition(p) {
  if (!p.age || !p.weight || !p.height) return null;
  const bmr = p.gender === "male"
    ? 10*p.weight + 6.25*p.height - 5*p.age + 5
    : 10*p.weight + 6.25*p.height - 5*p.age - 161;
  const mult = {sedentary:1.2,light:1.375,moderate:1.55,active:1.725,very_active:1.9};
  const tdee = bmr * (mult[p.activity]||1.375);
  const adj = {lose:-300,maintain:0,gain:250};
  const cal = Math.round(tdee + (adj[p.goal]||0));
  const bmi = (p.weight / ((p.height/100)**2));
  return {
    bmr: Math.round(bmr), tdee: Math.round(tdee), cal,
    bmi: bmi.toFixed(1),
    bmiLabel: bmi<18.5?"Поднормено":bmi<25?"Нормално":bmi<30?"Наднормено":"Затлъстяване",
    bmiColor: bmi<18.5?T.blue:bmi<25?T.green:bmi<30?T.amber:T.red,
    mealCal: Math.round(cal/3),
    mealCarbs: Math.round(cal*0.42/4/3),
    mealProtein: Math.round(cal*0.23/4/3),
    mealFat: Math.round(cal*0.35/9/3),
  };
}

