    good:  {bg:"rgba(34,197,94,.12)", border:"rgba(34,197,94,.3)",  color:"#86EFAC", icon:"✅"},
    warn:  {bg:"rgba(245,158,11,.12)", border:"rgba(245,158,11,.3)", color:"#FCD34D", icon:"⚠️"},
    danger:{bg:"rgba(239,68,68,.12)",  border:"rgba(239,68,68,.3)",  color:"#FCA5A5", icon:"🚨"},
